type Edge struct {
	to     int64
	start  int64
	end    int64
}

type Node struct {
	id    int64
	time  int64
}

type PriorityQueue []*Node

func (pq PriorityQueue) Len() int { return len(pq) }
func (pq PriorityQueue) Less(i, j int) bool { return pq[i].time < pq[j].time }
func (pq PriorityQueue) Swap(i, j int) { pq[i], pq[j] = pq[j], pq[i] }

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Node)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[:n-1]
	return item
}

func solve(n int64, edges [][]int64) int64 {
	graph := make(map[int64][]Edge)
	for _, e := range edges {
		u, v, start, end := e[0], e[1], e[2], e[3]
		graph[u] = append(graph[u], Edge{v, start, end})
	}

	dist := make([]int64, n)
	for i := range dist {
		dist[i] = -1
	}
	dist[0] = 0

	pq := make(PriorityQueue, 0)
	heap.Push(&pq, &Node{0, 0})

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*Node)
		u := current.id
		currentTime := current.time

		if u == n-1 {
			return currentTime
		}

		if currentTime > dist[u] {
			continue
		}

		for _, edge := range graph[u] {
			v := edge.to
			start := edge.start
			end := edge.end

			// The earliest time we can take this edge is max(currentTime, start)
			t := max(currentTime, start)
			if t > end {
				continue
			}
			arrivalTime := t + 1

			if dist[v] == -1 || arrivalTime < dist[v] {
				dist[v] = arrivalTime
				heap.Push(&pq, &Node{v, arrivalTime})
			}
		}
	}

	return dist[n-1]
}

